<template>
  <section id="about" class="about">

    <div class="container">

      <div class="section-header">

        <h2 class="section-title">

          <span class="gradient-text">
            {{ titlesLocale.first }}
          </span>

          {{ titlesLocale.second }}

        </h2>

      </div>

      <div class="about-grid">

        <div class="about-cards">

          <div
            v-for="(card, index) in aboutCards"
            :key="index"
            class="about-card"
          >

            <div class="card-header">

              <div class="icon-box icon-primary">

                <img
                  :src="card.icon"
                  :alt="card.alt"
                  class="about-icon"
                />

              </div>

              <div>

                <h3 class="gradient-text">
                  {{ card.title }}
                </h3>

                <p class="card-subtitle">
                  {{ card.subtitle }}
                </p>

              </div>

            </div>

            <div class="card-text">

              <p
                v-for="(text, i) in card.paragraphs"
                :key="i"
              >
                {{ text }}
              </p>

            </div>

          </div>

        </div>

      </div>

    </div>

  </section>
</template>

<script setup>
import { computed } from "vue"
import { useI18n } from "vue-i18n"
import { sobre, titles } from "@/data/sobre"

const { locale } = useI18n()

const aboutCards = computed(() => {

  if (locale.value === "pt") {
    return sobre.pt
  }
  return sobre.en
})

const titlesLocale = computed(() => {

  if (locale.value === "pt") {
    return titles.pt
  }
  return titles.en
})
</script>

