  transform: translateY(-5px);
  border-color: var(--card-destaque);
}

.card-header {
  display: flex;
  gap: 4px;
  margin-bottom: 20px;
  align-items: center;
}

.card-header h3 {
  font-size: 22px;
  line-height: 1.5;
}

.icon-box {
  padding: 8px;
  border-radius: 12px;
}

.about-icon {
  width: 35px;
  height: 35px;
  object-fit: contain;
}

.card-subtitle {
  color: var(--cor-texto-suave);
  font-size: 14px;
}

.card-text {
  color: var(--cor-texto-secundario);
}

.card-text p {
  font-size: 15px;
  margin-bottom: 16px;
  line-height: 1.5;
}

.card-text p:last-child {
  margin-bottom: 0;
}

@media (max-width: 1280px) {

  .about-cards {
    gap: 20px;
    justify-content: center;
  }

  .about-card {
    width: 400px;
    padding: 20px;
  }

  .card-header h3 {
    font-size: 20px;
  }

