    flex-direction: column;
    align-items: center;
    gap: 10px;
  }

  .about-card {
    width: 350px;
    border-radius: 16px;
    padding: 10px;
  }

  .card-header h3 {
    font-size: 16px;
  }

  .about-icon {
    width: 25px;
    height: 25px;
  }

  .card-subtitle {
    font-size: 12px;
  }

  .card-text p {
    font-size: 12px;
    margin-bottom: 10px;
  }

}
</style>