<template>
  <section id="contact" class="contact">

    <div class="container">

      <div class="contact-header">

        <h2>

          {{ contactLocale.titleFirst }}

          <span class="gradient-text">
            {{ contactLocale.titleSecond }}
          </span>

        </h2>

        <p>
          {{ contactLocale.description }}
        </p>

      </div>

      <div class="contact-grid">

        <div class="contact-info">

          <div class="card">

            <h3 class="gradient-text">
              {{ contactLocale.emailTitle }}
            </h3>

            <p>
              {{ contactLocale.contactInfo.email }}
            </p>

          </div>

          <div class="card">

            <h3 class="gradient-text">
              {{ contactLocale.locationTitle }}
            </h3>

            <p>
              {{ contactLocale.contactInfo.location }}
            </p>

          </div>

          <div class="social-icons">

            <h3 class="gradient-text">
              {{ contactLocale.socialTitle }}
            </h3>

            <p>
              {{ contactLocale.socialDescription }}
            </p>

            <div class="social-links">

              <a v-for="social in socialLinks" :key="social.nome" :href="social.link" target="_blank"
                rel="noopener noreferrer">

                <img :src="social.icon" :alt="social.nome" class="social-icon" />

              </a>

            </div>

          </div>

        </div>

        <!--
        <div class="form-card">

          <form v-if="!success" ref="formRef" @submit.prevent="sendEmail">

            <div class="grid">

              <input v-model="form.name" type="text" name="name" required
                :placeholder="contactLocale.namePlaceholder" />

              <input v-model="form.email" type="email" name="email" required
                :placeholder="contactLocale.emailPlaceholder" />

            </div>

            <select v-model="form.subject" name="subject" required>

              <option value="">
                {{ contactLocale.selectSubject }}
              </option>

              <option v-for="item in contactLocale.subjects" :key="item" :value="item">
                {{ item }}
              </option>

            </select>

            <select v-model="form.budget" name="budget" required>

              <option value="">
                {{ contactLocale.selectBudget }}
              </option>

              <option v-for="item in contactLocale.budgets" :key="item" :value="item">
                {{ item }}
              </option>

            </select>

            <textarea v-model="form.message" name="message" rows="5" required
              :placeholder="contactLocale.messagePlaceholder"></textarea>

            <button type="submit">
              {{ contactLocale.send }}
            </button>

            <Transition name="fade-slide">

              <ReCaptcha v-if="showCaptcha" ref="captchaRef" sitekey="6LcI-WQsAAAAAOEzVJby3HCnRWkYpY_-BwAJROXQ"
                theme="dark" class="recaptcha" @verify="onCaptchaVerified" />


            </Transition>

          </form>

          <div v-else class="success">

            <h3>
              {{ contactLocale.messageSentTitle }}
            </h3>

            <p>
              {{ contactLocale.messageSentDescription }}
            </p>

          </div>

        </div>
      -->

      </div>
    </div>

  </section>
</template>

<script setup>
import { ref, computed } from "vue"
import { useI18n } from "vue-i18n"

import emailjs from "@emailjs/browser"
import ReCaptcha from "vue3-recaptcha2"

import { contact, socialLinks } from "@/data/contact"

const { locale } = useI18n()

const contactLocale = computed(() => {

  if (locale.value === "en") {
    return contact.en
  }

  return contact.pt

})

const { t, tm } = useI18n()

const formRef = ref(null)

const captchaToken = ref(null)

const success = ref(false)

const form = ref({
  name: "",
  email: "",
  subject: "",
  budget: "",
  message: ""
})


const showCaptcha = computed(() => {
  return (
    form.value.name.trim() &&
    form.value.email.trim() &&
    form.value.subject.trim() &&
    form.value.budget.trim() &&
    form.value.message.trim()
  )
})

const captchaRef = ref(null)

const onCaptchaVerified = (token) => {
  captchaToken.value = token
}

const sendEmail = async () => {

  if (!captchaToken.value) {
    alert(t("contact.robotConfirm"))
    return
  }


  try {

    const response = await fetch("https://bp-website-six.vercel.app/api/verify-captcha", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        token: captchaToken.value
      })
    })

    const data = await response.json()

    console.log("captcha response:", data)

    if (!data.success) {
      alert("Captcha inválido")
      return
    }

    await emailjs.sendForm(
      "black_paladins_gmail",
      "contact_us_template",
      formRef.value,
      "dHgVg-7Kh_iUX8y8B"
    )

    success.value = true

    form.value = {
      name: "",
      email: "",
      subject: "",
      budget: "",
      message: ""
    }

    captchaToken.value = null

    setTimeout(() => {
      success.value = false
    }, 3000)

  }
  catch (error) {
    console.log(error)
    alert("Erro ao enviar formulário")
  }
}
</script>

