  background: var(--bg-destaque);
}

.grid {
  display: flex;
  gap: 20px;
}

.grid input {
  flex: 1;
}

input,
textarea,
select {
  width: 100%;
  padding: 16px;
  margin-bottom: 20px;
  border-radius: 12px;
  border: 1px solid var(--card-base);
  background: var(--bg-secundario);
  color: var(--cor-texto-principal);
